import{_ as a,o as i,c as e,ag as d}from"./chunks/framework.DGzMGr_a.js";const b=JSON.parse('{"title":"从 Minecraft 迁移","description":"","frontmatter":{},"headers":[],"relativePath":"guide/migration.md","filePath":"guide/migration.md","lastUpdated":1783761543000}'),r={name:"guide/migration.md"};function l(o,t,n,s,h,c){return i(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="从-minecraft-迁移" tabindex="-1">从 Minecraft 迁移 <a class="header-anchor" href="#从-minecraft-迁移" aria-label="Permalink to &quot;从 Minecraft 迁移&quot;">​</a></h1><p>已经在玩 Minecraft？这张表帮你 5 分钟搞懂 MineClonia 的差异。</p><h2 id="速查对照表" tabindex="-1">速查对照表 <a class="header-anchor" href="#速查对照表" aria-label="Permalink to &quot;速查对照表&quot;">​</a></h2><h3 id="基本差异" tabindex="-1">基本差异 <a class="header-anchor" href="#基本差异" aria-label="Permalink to &quot;基本差异&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>Minecraft</th><th>MineClonia</th></tr></thead><tbody><tr><td>价格</td><td>¥165 (Java) / 免费 (基岩)</td><td><strong>完全免费</strong></td></tr><tr><td>引擎</td><td>自研</td><td>Luanti (开源)</td></tr><tr><td>Mod 支持</td><td>Forge/Fabric</td><td>原生 Lua Modding</td></tr><tr><td>最大地图</td><td>6000万×6000万</td><td><strong>无限</strong>（理论值）</td></tr><tr><td>红石</td><td>Redstone</td><td><strong>不存在</strong>，用 mesecons 替代</td></tr><tr><td>附魔</td><td>附魔台</td><td>附魔台（机制略有不同）</td></tr><tr><td>酿造</td><td>酿造台</td><td>酿造台（配方基本一致）</td></tr><tr><td>下界</td><td>Nether</td><td>Nether</td></tr><tr><td>末地</td><td>End</td><td><strong>不存在</strong></td></tr></tbody></table><h3 id="物品名称对照" tabindex="-1">物品名称对照 <a class="header-anchor" href="#物品名称对照" aria-label="Permalink to &quot;物品名称对照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Minecraft</th><th>MineClonia</th><th>备注</th></tr></thead><tbody><tr><td>钻石</td><td>Diamond</td><td>一致</td></tr><tr><td>铁锭</td><td>Iron Ingot</td><td>一致</td></tr><tr><td>红石粉</td><td>Mese Crystal</td><td><strong>名称不同，功能类似</strong></td></tr><tr><td>红石火把</td><td>Mesecon Torch</td><td>对应物</td></tr><tr><td>活塞</td><td>Piston</td><td>对应物</td></tr><tr><td>命令方块</td><td>Command Block</td><td>需要权限</td></tr><tr><td>附魔之瓶</td><td>XP Bottle</td><td>一致</td></tr></tbody></table><h3 id="机制差异" tabindex="-1">机制差异 <a class="header-anchor" href="#机制差异" aria-label="Permalink to &quot;机制差异&quot;">​</a></h3><h4 id="红石-→-mesecons" tabindex="-1">红石 → Mesecons <a class="header-anchor" href="#红石-→-mesecons" aria-label="Permalink to &quot;红石 → Mesecons&quot;">​</a></h4><p>MineClonia 用 <strong>Mesecons</strong> 替代红石系统：</p><ul><li>Mese Crystal（美赛水晶）= 红石粉</li><li>Mesecon Torch = 红石火把</li><li>逻辑门、活塞、中继器等都有对应物</li><li>布线规则和红石<strong>不完全相同</strong>，需要重新学习</li></ul><div class="tip custom-block"><p class="custom-block-title">建议</p><p>如果你是红石玩家，先在创造模式里玩一下 Mesecons， 理解信号传播规则后再搞复杂电路。</p></div><h4 id="附魔" tabindex="-1">附魔 <a class="header-anchor" href="#附魔" aria-label="Permalink to &quot;附魔&quot;">​</a></h4><ul><li>附魔台存在，但附魔等级和效果与 MC 有差异</li><li>需要青金石（Lapis Lazuli）作为附魔材料</li><li>附魔书可以通过钓鱼获得</li></ul><h4 id="酿造" tabindex="-1">酿造 <a class="header-anchor" href="#酿造" aria-label="Permalink to &quot;酿造&quot;">​</a></h4><ul><li>酿造台、药水瓶、材料基本一致</li><li>部分药水效果有差异</li><li>烈焰粉仍然是燃料</li></ul><h4 id="没有的东西" tabindex="-1">没有的东西 <a class="header-anchor" href="#没有的东西" aria-label="Permalink to &quot;没有的东西&quot;">​</a></h4><p>以下是 MC 有但 MineClonia <strong>没有</strong>的内容：</p><ul><li>❌ 末地 / 末影龙</li><li>❌ 潜影盒</li><li>❌ 鞘翅 / 烟花火箭飞行</li><li>❌ 劫掠 / 村庄英雄</li><li>❌ 潮涌核心</li><li>❌ 潜声传感器</li><li>❌ 细雪</li></ul><h4 id="多出来的东西" tabindex="-1">多出来的东西 <a class="header-anchor" href="#多出来的东西" aria-label="Permalink to &quot;多出来的东西&quot;">​</a></h4><p>MineClonia 有一些 MC <strong>没有</strong>的内容：</p><ul><li>✅ 僵尸围城（Zombie Siege）系统</li><li>✅ 袭击（Raid）系统</li><li>✅ 更丰富的天气系统</li><li>✅ 内置的成就系统</li><li>✅ 内置的物品百科（按 I 键查看）</li></ul><h2 id="创造模式" tabindex="-1">创造模式 <a class="header-anchor" href="#创造模式" aria-label="Permalink to &quot;创造模式&quot;">​</a></h2><p>和 MC 一样有创造模式：</p><ul><li>按 <code>K</code> 切换飞行</li><li>物品栏包含所有方块和物品</li><li>可以直接放置任何方块</li></ul><h2 id="服务器" tabindex="-1">服务器 <a class="header-anchor" href="#服务器" aria-label="Permalink to &quot;服务器&quot;">​</a></h2><p>MineClonia 的多人游戏基于 Luanti 服务器：</p><ul><li>主菜单 → <strong>Join Game</strong> (加入游戏)</li><li>可以直接输入服务器 IP 连接</li><li>也可以浏览公共服务器列表</li></ul><div class="info custom-block"><p class="custom-block-title">国内服务器</p><p>国内 MineClonia 服务器较少，可以：</p><ul><li>自己开服（Luanti 自带服务器功能）</li><li>在 Luanti 社区寻找中文服务器</li></ul></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-存档能通用吗" tabindex="-1">Q: 存档能通用吗？ <a class="header-anchor" href="#q-存档能通用吗" aria-label="Permalink to &quot;Q: 存档能通用吗？&quot;">​</a></h3><p><strong>不能。</strong> Minecraft 和 MineClonia 的存档格式完全不同。</p><h3 id="q-mod-能通用吗" tabindex="-1">Q: Mod 能通用吗？ <a class="header-anchor" href="#q-mod-能通用吗" aria-label="Permalink to &quot;Q: Mod 能通用吗？&quot;">​</a></h3><p><strong>不能。</strong> 两个游戏的 Mod 系统完全不同。但 MineClonia 有自己的 Mod 生态。</p><h3 id="q-材质包能用吗" tabindex="-1">Q: 材质包能用吗？ <a class="header-anchor" href="#q-材质包能用吗" aria-label="Permalink to &quot;Q: 材质包能用吗？&quot;">​</a></h3><p><strong>不能直接用。</strong> 但 MineClonia 支持自定义材质包，格式与 MC 不同。</p><h3 id="q-操作习惯能保持吗" tabindex="-1">Q: 操作习惯能保持吗？ <a class="header-anchor" href="#q-操作习惯能保持吗" aria-label="Permalink to &quot;Q: 操作习惯能保持吗？&quot;">​</a></h3><p><strong>基本可以。</strong> WASD 移动、空格跳跃、左键挖右键放都一样。背包和合成界面略有差异。</p>',38)])])}const m=a(r,[["render",l]]);export{b as __pageData,m as default};
